import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, Tag, Trash2, X, layers, Palette } from 'lucide-react';
import '../styles/Categorias.css';

const Categorias = () => {
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('despesa');
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ nome: '', cor: '#4361ee' });

  useEffect(() => {
    buscarCategorias();
  }, []);

  async function buscarCategorias() {
    setLoading(true);
    const { data } = await supabase.from('categorias').select('*').order('nome');
    setCategorias(data || []);
    setLoading(false);
  }

  async function handleSalvar(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();

    const { error } = await supabase.from('categorias').insert([{
      user_id: user.id,
      nome: form.nome,
      tipo: activeTab,
      cor: form.cor
    }]);

    if (!error) {
      setForm({ nome: '', cor: '#4361ee' });
      setShowModal(false);
      buscarCategorias();
    }
  }

  async function excluirCategoria(id) {
    if (window.confirm("Deseja excluir esta categoria?")) {
      await supabase.from('categorias').delete().eq('id', id);
      buscarCategorias();
    }
  }

  const categoriasFiltradas = categorias.filter(c => c.tipo === activeTab);

  return (
    <div className="categorias-container fade-in">
      <header className="categorias-header">
        <div>
          <h2>Categorias</h2>
          <p>Organize seus fluxos financeiros</p>
        </div>
        <div className="tab-switcher">
          <button 
            className={activeTab === 'provento' ? 'active' : ''} 
            onClick={() => setActiveTab('provento')}
          >
            Entradas
          </button>
          <button 
            className={activeTab === 'despesa' ? 'active' : ''} 
            onClick={() => setActiveTab('despesa')}
          >
            Saídas
          </button>
        </div>
      </header>

      <div className="categorias-grid">
        {loading ? (
          <p>Carregando...</p>
        ) : categoriasFiltradas.length > 0 ? (
          categoriasFiltradas.map(cat => (
            <div key={cat.id} className="categoria-card" style={{ borderLeft: `6px solid ${cat.cor}` }}>
              <div className="cat-info">
                <div className="cat-dot" style={{ backgroundColor: cat.cor }}></div>
                <strong>{cat.nome}</strong>
              </div>
              <button onClick={() => excluirCategoria(cat.id)} className="btn-del-cat">
                <Trash2 size={18} />
              </button>
            </div>
          ))
        ) : (
          <div className="empty-cat">Nenhuma categoria encontrada para {activeTab}s.</div>
        )}
      </div>

      <button className="fab-button category" onClick={() => setShowModal(true)}>
        <Plus size={28} />
      </button>

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content side-modal fade-in" onClick={e => e.stopPropagation()}>
            <div className="modal-header-simple">
              <h3>Nova Categoria de {activeTab}</h3>
              <button className="close-btn" onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>

            <form onSubmit={handleSalvar} className="modal-form">
              <div className="input-group">
                <label><Tag size={14}/> Nome da Categoria</label>
                <input 
                  type="text" required value={form.nome} 
                  onChange={e => setForm({...form, nome: e.target.value})} 
                  placeholder="Ex: Assinaturas, Bônus..."
                />
              </div>
              
              <div className="input-group">
                <label><Palette size={14}/> Cor de Identificação</label>
                <input 
                  type="color" value={form.cor} 
                  onChange={e => setForm({...form, cor: e.target.value})} 
                  className="color-picker"
                />
              </div>

              <button type="submit" className="btn-confirm-cat" style={{ backgroundColor: activeTab === 'provento' ? '#16a34a' : '#ef4444' }}>
                Criar Categoria
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Categorias;
